{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "run-elegant-review/findings.schema.json",
  "title": "Elegant Review Findings",
  "description": "30思考法 × C1-C4 マトリクスと variable_abstraction を含む findings の構造定義。",
  "type": "object",
  "required": ["version", "target", "paradigm_findings", "four_conditions", "variable_abstraction", "thought_method_coverage"],
  "properties": {
    "version": {"type": "integer", "const": 1},
    "target": {
      "type": "object",
      "required": ["type", "path", "reviewed_at"],
      "properties": {
        "type": {"type": "string", "enum": ["skill", "rubric", "proposal", "kit-component", "script", "config", "agent", "custom"]},
        "path": {"type": "string"},
        "reviewed_at": {"type": "string", "format": "date-time"}
      }
    },
    "loop_count": {"type": "integer", "minimum": 0, "maximum": 3},
    "paradigm_findings": {
      "type": "array",
      "minItems": 0,
      "maxItems": 30,
      "items": {"$ref": "#/definitions/paradigm_finding"}
    },
    "thought_method_coverage": {
      "type": "object",
      "required": ["used", "skipped_with_reason", "total"],
      "properties": {
        "used": {
          "type": "array",
          "items": {"type": "string"}
        },
        "skipped_with_reason": {
          "type": "array",
          "items": {
            "type": "object",
            "required": ["method", "reason"],
            "properties": {
              "method": {"type": "string"},
              "reason": {"type": "string", "minLength": 1}
            }
          }
        },
        "total": {"type": "integer", "const": 30}
      }
    },
    "four_conditions": {
      "type": "object",
      "required": ["C1", "C2", "C3", "C4"],
      "properties": {
        "C1": {"$ref": "#/definitions/condition_verdict"},
        "C2": {"$ref": "#/definitions/condition_verdict"},
        "C3": {"$ref": "#/definitions/condition_verdict"},
        "C4": {"$ref": "#/definitions/condition_verdict"}
      }
    },
    "variable_abstraction": {
      "type": "array",
      "items": {
        "type": "object",
        "required": ["concrete_value", "variable_name", "source_trace"],
        "properties": {
          "concrete_value": {"type": "string"},
          "variable_name": {"type": "string", "pattern": "^\\{\\{[A-Za-z_][A-Za-z0-9_]*\\}\\}$"},
          "default_value": {"type": "string"},
          "source_trace": {"type": "string"}
        }
      }
    },
    "total_score": {"type": "number", "minimum": 0.0, "maximum": 1.0}
  },
  "definitions": {
    "paradigm_finding": {
      "type": "object",
      "required": ["paradigm_id", "paradigm_name", "category", "agent", "observations", "condition_matrix", "issues", "score"],
      "properties": {
        "paradigm_id": {"type": "integer", "minimum": 1, "maximum": 30},
        "paradigm_name": {"type": "string"},
        "category": {"type": "string", "enum": ["A-logical", "B-structural", "C-meta", "D-divergent", "E-system", "F-strategic", "G-problem"]},
        "agent": {"type": "string", "enum": ["elegant-logical-structural-analyst", "elegant-meta-divergent-analyst", "elegant-system-strategic-analyst"]},
        "observations": {"type": "array", "minItems": 1, "items": {"type": "string"}},
        "condition_matrix": {
          "type": "object",
          "required": ["C1", "C2", "C3", "C4"],
          "properties": {
            "C1": {"$ref": "#/definitions/condition_verdict"},
            "C2": {"$ref": "#/definitions/condition_verdict"},
            "C3": {"$ref": "#/definitions/condition_verdict"},
            "C4": {"$ref": "#/definitions/condition_verdict"}
          },
          "additionalProperties": false
        },
        "issues": {
          "type": "array",
          "items": {
            "type": "object",
            "required": ["condition", "severity", "bucket", "description", "recommended_intervention"],
            "properties": {
              "condition": {"type": "string", "enum": ["C1", "C2", "C3", "C4"]},
              "severity": {"type": "string", "enum": ["low", "medium", "high", "critical"]},
              "bucket": {"type": "string", "enum": ["dependency-loop", "eval-log", "hook-ci", "rubric-governance", "dogfooding", "variable-abstraction", "doc", "schema", "other"]},
              "description": {"type": "string"},
              "recommended_intervention": {"type": "string"},
              "condition_signal": {"type": "string", "enum": ["contradiction", "omission", "inconsistency", "dependency_break", "smell"]},
              "location": {
                "type": "object",
                "required": ["file"],
                "properties": {
                  "file": {"type": "string"},
                  "line": {"type": "integer", "minimum": 1},
                  "section": {"type": "string"}
                }
              },
              "depends_on": {
                "type": "array",
                "items": {"type": "string", "pattern": "^F-[0-9]{4}$"}
              },
              "root_cause": {"type": "string"}
            }
          }
        },
        "score": {"type": "number", "minimum": 0.0, "maximum": 1.0},
        "reusable_abstraction": {"type": "string"},
        "template_variables": {"type": "array", "items": {"type": "string"}},
        "reuse_surface": {"type": "string", "enum": ["skill", "template", "script-frontmatter", "hook", "config", "governance-log", "adapter", "rubric", "reference", "none"]},
        "negative_cases": {"type": "array", "items": {"type": "string"}},
        "re_audit_trigger": {"type": "string"}
      }
    },
    "condition_verdict": {
      "type": "object",
      "required": ["verdict", "evidence"],
      "properties": {
        "verdict": {"type": "string", "enum": ["PASS", "FAIL", "PARTIAL"]},
        "evidence": {"type": "array", "minItems": 1, "items": {"type": "string"}},
        "violation_count": {"type": "integer", "minimum": 0}
      }
    }
  }
}

{
  "version": 1,
  "conditions": [
    {
      "id": "C1",
      "name": "consistency",
      "label_ja": "矛盾なし",
      "definition": "内部の主張・ルール間に論理矛盾が存在しない",
      "check_method": {
        "type": "claim-graph",
        "detector": "contradiction-edge",
        "pass_when": "contradiction_edges == 0"
      },
      "severity_on_fail": "critical"
    },
    {
      "id": "C2",
      "name": "completeness",
      "label_ja": "漏れなし",
      "definition": "対象スコープに必要な要素がMECEに揃っている",
      "check_method": {
        "type": "checklist",
        "source": "required-element-list",
        "pass_when": "missing_elements == 0"
      },
      "severity_on_fail": "high"
    },
    {
      "id": "C3",
      "name": "coherence",
      "label_ja": "整合性あり",
      "definition": "上位仕様 (24章正本 / parent rubric) と整合している",
      "check_method": {
        "type": "rubric-diff",
        "against": [
          "ref-skill-design-rubric",
          "24-chapter-canonical-spec"
        ],
        "pass_when": "violations == 0"
      },
      "severity_on_fail": "critical"
    },
    {
      "id": "C4",
      "name": "dependency",
      "label_ja": "依存関係整合",
      "definition": "参照・前提・順序が破綻していない",
      "check_method": {
        "type": "dag",
        "operation": "topological-sort",
        "pass_when": "cycles == 0 AND dangling_refs == 0"
      },
      "severity_on_fail": "high"
    }
  ],
  "severity_label_map": {
    "_comment": "finding の機械観測 signal (finding.schema.json) → 運用ラベル (findings.schema.json issues.severity) の変換表。severity_on_fail (C1/C3→critical, C2/C4→high) と整合 (LS-010)",
    "contradiction": "critical",
    "inconsistency": "critical",
    "omission": "high",
    "dependency_break": "high",
    "smell": "low"
  },
  "completion": {
    "rule": "ALL conditions must PASS",
    "loop_limit": 3,
    "on_loop_exhausted": "escalate-to-human"
  }
}
